import React from 'react';
import { useSelector } from 'react-redux';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';

const UnauthenticatedMenu = ({ categories, handleDrawerClose }) => {
    const players = useSelector((state) => state.players.players);

    const filteredCategories = categories.map(category => {
        const subMenusWithPlayers = category.subMenu.filter(subMenu => {
            return players.some(player => {
                const matchCategory = player.category.includes(category.mainMenu);
                const matchSubCategory = player.subCategory.includes(subMenu);
                return matchCategory && matchSubCategory;
            });
        });

        // Här inkluderas även huvudmenyer som har minst en undermeny med spelare
        if (subMenusWithPlayers.length > 0) {
            return { ...category, subMenu: subMenusWithPlayers };
        } else {
            return null; // Om ingen undermeny matchar, returnera null för att filtrera bort kategorin
        }
    }).filter(category => category !== null); // Filtrera bort null-värden från arrayen

    return (
        <List component="div" disablePadding>
            {filteredCategories.map((category) => (
                <ListItem key={category._id}>
                    <ListItemText primary={category.mainMenu} />
                </ListItem>
            ))}
        </List>
    );
};

export default UnauthenticatedMenu;
